import{_ as a,a as n,b as i,c as t,d,e as o,f as s,g as r}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as l,o as h,c,a2 as p}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Other/federated-distributed-index.md","filePath":"vi-VN/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),u={name:"vi-VN/Other/federated-distributed-index.md"};function b(g,e,m,f,k,x){return h(),c("div",null,[...e[0]||(e[0]=[p('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>Federated distributed index cho phép nhiều ImgBed sites share file lists với nhau.</p><p>Hiểu đơn giản:</p><ul><li>Bạn có thể share selected folders từ site của mình cho người khác.</li><li>Bạn có thể join node khác và sync shared file list của node đó vào admin panel của mình.</li><li>Federated files chủ yếu dùng để browse, search và mở links. Chúng không được re-upload vào storage của bạn.</li></ul><h2 id="cau-hinh-o-đau" tabindex="-1">Cấu hình ở đâu <a class="header-anchor" href="#cau-hinh-o-đau" aria-label="Permalink to &quot;Cấu hình ở đâu&quot;">​</a></h2><p>Mở:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="Local federation node" loading="lazy"></p><p>Trang có ba tabs:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td>Local Node</td><td>Enable node của bạn, confirm public domain, chọn shared folders và update outbound index</td></tr><tr><td>Nodes I Joined</td><td>Manage các ImgBed nodes khác mà bạn đã join</td></tr><tr><td>Nodes Joining Me</td><td>Manage requests từ người khác muốn join node của bạn</td></tr></tbody></table><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li>Mở <code>Local Node</code>.</li><li>Bật <code>Enable</code>.</li><li>Chọn folders muốn share trong <code>Sync folders</code>.</li><li>Nhấn <code>Update Outbound Index</code>.</li><li>Nếu ImgBed detect domain change, confirm current domain đúng trước khi tiếp tục.</li></ol><p>Bạn có thể chọn nhiều sync folders.</p><p>Nếu sync folder list trống, tất cả folders sẽ được share.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>Public domain là site URL mà nodes khác dùng để access node của bạn.</p><p>ImgBed tự detect. Bạn không cần nhập thủ công. Lần đầu update index, ImgBed sẽ hỏi current access URL có phải production domain không.</p><p>Nếu sau này đổi domain, khi update index sẽ hỏi confirmation lại.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders quyết định files nào được share với federation nodes.</p><p>Ví dụ, nếu bạn chỉ chọn:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>Nodes khác chỉ thấy files trong hai directories đó.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>Thao tác này update file list mà nodes khác có thể sync từ bạn.</p><p>Dùng khi:</p><ul><li>Bạn enable federation lần đầu.</li><li>Bạn upload files muốn share.</li><li>Bạn đổi sync folders.</li><li>Bạn đổi public domain và cần confirm.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> là nơi bạn subscribe nodes khác.</p><p><img src="`+n+'" alt="Nodes I joined" loading="lazy"></p><h3 id="gui-request-join-node-khac" tabindex="-1">Gửi Request Join Node Khác <a class="header-anchor" href="#gui-request-join-node-khac" aria-label="Permalink to &quot;Gửi Request Join Node Khác&quot;">​</a></h3><ol><li>Xin invitation link từ owner phía bên kia.</li><li>Paste vào input box.</li><li>Nhấn <code>Request to Join</code>.</li><li>Chờ owner phía bên kia approve trong admin panel của họ.</li></ol><p>Sau khi approval, node status sẽ thành approved.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> sync file lists từ các nodes bạn đã joined.</p><p>Dùng khi:</p><ul><li>Owner phía bên kia vừa approve request của bạn.</li><li>Owner phía bên kia báo shared content đã update.</li><li>Bạn muốn refresh tất cả joined federation file lists.</li></ul><p>Để update chỉ một node, nhấn <code>Update Index</code> trên node card đó.</p><p><img src="'+i+'" alt="Update index" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>Nếu không muốn sync một node nữa, nhấn <code>Unsubscribe</code>.</p><p>Sau khi unsubscribe, federated index của node đó sẽ bị xóa khỏi local site của bạn.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> là nơi xử lý requests từ người khác.</p><p><img src="'+t+'" alt="Nodes joining me" loading="lazy"></p><h3 id="generate-invitation-link" tabindex="-1">Generate Invitation Link <a class="header-anchor" href="#generate-invitation-link" aria-label="Permalink to &quot;Generate Invitation Link&quot;">​</a></h3><ol><li>Đảm bảo local node đã enabled.</li><li>Nhấn <code>Update Outbound Index</code> ít nhất một lần để ImgBed confirm public domain.</li><li>Mở <code>Nodes Joining Me</code>.</li><li>Nhấn <code>Reset Invitation Link</code>.</li><li>Copy invitation link và gửi cho owner phía bên kia.</li></ol><p>Nếu invitation link trống, thường là public domain chưa được confirm. Quay lại <code>Local Node</code> và nhấn <code>Update Outbound Index</code>.</p><h3 id="xu-ly-join-requests" tabindex="-1">Xử lý Join Requests <a class="header-anchor" href="#xu-ly-join-requests" aria-label="Permalink to &quot;Xử lý Join Requests&quot;">​</a></h3><p>Khi ai đó submit request, nó xuất hiện trong list <code>Nodes Joining Me</code>.</p><table tabindex="0"><thead><tr><th>Action</th><th>Meaning</th></tr></thead><tbody><tr><td>Approve</td><td>Cho phép node bên kia sync shared file list của bạn</td></tr><tr><td>Reject</td><td>Từ chối join request</td></tr><tr><td>Delete</td><td>Xóa finished record</td></tr><tr><td>Check Status</td><td>Kiểm tra phía bên kia còn giữ relationship này không</td></tr></tbody></table><p>Sau approval, phía bên kia vẫn cần nhấn <code>Update Inbound Index</code> trước khi shared files của bạn xuất hiện ở đó.</p><p><img src="'+d+'" alt="Approve invited node" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>Sau khi relationship approved, nhấn <code>Message</code> trên node card.</p><p>Messages chỉ dùng để trao đổi về federation relationship. Chúng không thay đổi files, tags, directories hoặc permissions.</p><p><img src="'+o+'" alt="Messages" loading="lazy"></p><h2 id="xem-federated-files" tabindex="-1">Xem Federated Files <a class="header-anchor" href="#xem-federated-files" aria-label="Permalink to &quot;Xem Federated Files&quot;">​</a></h2><p>Sau khi sync hoàn tất, quay lại admin file list.</p><p>Ở đầu page, chuyển giữa local files và federated files. Trong federated files, bạn có thể browse synced content.</p><p>Federated files chủ yếu để viewing, searching, previewing và copying links. Chúng không phải local files, nên bạn không thể move, delete, retag hoặc back up từ site của mình.</p><p><img src="'+s+'" alt="Federated files in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="vi-sao-he-thong-yeu-cau-reapply-vi-khong-co-relationship-record" tabindex="-1">Vì sao hệ thống yêu cầu Reapply vì không có Relationship Record? <a class="header-anchor" href="#vi-sao-he-thong-yeu-cau-reapply-vi-khong-co-relationship-record" aria-label="Permalink to &quot;Vì sao hệ thống yêu cầu Reapply vì không có Relationship Record?&quot;">​</a></h3><p>Thường nghĩa là phía bên kia đã delete bạn và xóa record, nên relationship không còn tìm được. Hãy submit join request mới.</p><p><img src="'+r+'" alt="Reapply when no relationship record exists" loading="lazy"></p><h3 id="vi-sao-join-roi-van-khong-thay-files" tabindex="-1">Vì sao join rồi vẫn không thấy Files? <a class="header-anchor" href="#vi-sao-join-roi-van-khong-thay-files" aria-label="Permalink to &quot;Vì sao join rồi vẫn không thấy Files?&quot;">​</a></h3><p>Kiểm tra:</p><ol><li>Owner phía bên kia đã approve request của bạn.</li><li>Owner phía bên kia đã nhấn <code>Update Outbound Index</code>.</li><li>Bạn đã nhấn <code>Update Inbound Index</code>.</li><li>Sync folders của owner phía bên kia có chứa directories họ muốn share.</li></ol><h3 id="domain-change-detected-thi-lam-gi" tabindex="-1">Domain Change Detected thì làm gì? <a class="header-anchor" href="#domain-change-detected-thi-lam-gi" aria-label="Permalink to &quot;Domain Change Detected thì làm gì?&quot;">​</a></h3><p>Nếu bạn đang mở admin panel bằng production domain, confirm và tiếp tục.</p><p>Nếu đang dùng temporary address, cancel, mở lại admin panel bằng production domain rồi thử lại.</p><h3 id="empty-sync-folder-list-nghia-la-gi" tabindex="-1">Empty Sync Folder List nghĩa là gì? <a class="header-anchor" href="#empty-sync-folder-list-nghia-la-gi" aria-label="Permalink to &quot;Empty Sync Folder List nghĩa là gì?&quot;">​</a></h3><p>Empty sync folder list nghĩa là share tất cả folders.</p><p>Nếu chỉ muốn share vài directories, hãy chọn folders thủ công.</p><h3 id="khac-nhau-giua-outbound-va-inbound-index-updates" tabindex="-1">Khác nhau giữa Outbound và Inbound Index Updates <a class="header-anchor" href="#khac-nhau-giua-outbound-va-inbound-index-updates" aria-label="Permalink to &quot;Khác nhau giữa Outbound và Inbound Index Updates&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Simple Meaning</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>Update những gì người khác có thể sync từ tôi</td></tr><tr><td>Update Inbound Index</td><td>Update những gì tôi đã sync từ người khác</td></tr></tbody></table>',78)])])}const I=l(u,[["render",b]]);export{q as __pageData,I as default};
